const input = $input.first().json;
const required = ['to', 'from', 'subject', 'html'];
const missing = required.filter(f => !input[f]);
if (missing.length > 0) {
  throw new Error(`[Utility] Send Email: missing required input(s): ${missing.join(', ')}`);
}
return [{ json: input }];
